SELECT DATE(stickied_date) AS sticky_date, COUNT(*) AS stickied_count
FROM stickied_comments
GROUP BY sticky_date;

SELECT c.*
FROM comments c
JOIN stickied_comments s ON c.comment_id = s.comment_id;

SELECT user_id, username
FROM users
WHERE user_id IN (
    SELECT user_id FROM user_badges WHERE badge_name = 'Helpful User'
)
AND user_id IN (
    SELECT reporter_id FROM userReports WHERE reason = 'Trolling'
)
AND user_id IN (
    SELECT author_id FROM links WHERE category = 'Technology'
)
AND user_id IN (
    SELECT stickied_by FROM stickied_comments
);

SELECT DISTINCT reporter_id 
FROM userReports 
WHERE reporter_id IS NOT NULL;

SELECT user_id, username
FROM users
WHERE user_id IN (
  SELECT reported_id
  FROM userReports
) AND user_id NOT IN (
  SELECT user_id
  FROM user_badges
)
ORDER BY username ASC;

SELECT user_id, MAX(upvote_date) AS latest_upvote_date
FROM upvote_logs
GROUP BY user_id;
